import { withPayload } from "@payloadcms/next/withPayload";
import { readFileSync } from "fs";
import { join } from "path";

// Load WordPress → Next.js redirect map (generated by scripts/convert-wp-posts.mjs)
let wpRedirects = [];
try {
  const raw = readFileSync(join(process.cwd(), "scripts", "redirects.json"), "utf-8");
  wpRedirects = JSON.parse(raw);
} catch {
  // Redirects file may not exist yet before first conversion
}

/** @type {import('next').NextConfig} */
const nextConfig = {
  eslint: {
    // Lint is run separately in CI; don't block production builds
    ignoreDuringBuilds: true,
  },

  experimental: {
    // Inline critical CSS and defer non-critical styles to eliminate render-blocking
    optimizeCss: true,
  },

  images: {
    formats: ["image/webp"],
    minimumCacheTTL: 86400,
    remotePatterns: [
      {
        protocol: "https",
        hostname: "i0.wp.com",
        pathname: "/luxewindowworks.com/wp-content/uploads/**",
      },
      {
        protocol: "https",
        hostname: "img.youtube.com",
      },
    ],
  },

  async headers() {
    return [
      {
        // Static images in /public/images — serve with 1-year immutable cache
        // so CDN edges and browsers don't re-fetch on every visit/PageSpeed run
        source: "/images/:path*",
        headers: [
          {
            key: "Cache-Control",
            value: "public, max-age=31536000, immutable",
          },
        ],
      },
    ];
  },

  async redirects() {
    const staticRedirects = [
      {
        source: '/explore-motorized-shades-plantation-shutters-have-a-question-lets-start-the-c',
        destination: '/blog',
        permanent: true,
      },
      {
        source: '/services',
        destination: '/',
        permanent: true,
      },
      {
        source: '/case-studies',
        destination: '/blog',
        permanent: true,
      },
      {
        source: '/why-motorized-shades-fail-in-northern-idaho-and-how-to-fix-them',
        destination: '/blog/why-motorized-shades-fail-in-northern-idaho-and-how-to-fix-them',
        permanent: true,
      },
      {
        source: '/',
        has: [{ type: 'query', key: 'page_id' }],
        destination: '/',
        permanent: true,
      },
    ];

    return [
      ...staticRedirects,
      ...wpRedirects.map((r) => ({
        source: r.source,
        destination: r.destination,
        permanent: true, // 301 redirect — preserves SEO juice
      })),
    ];
  },
};

export default withPayload(nextConfig);
